using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search capability using the DuckDuckGo Instant Answer API.
/// </summary>
public sealed class WebSearchTool
{
    private readonly HttpClient _httpClient;

    public WebSearchTool(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    [Description("Searches the web for information on a given query and returns relevant results. Use this to find facts, articles, and data about any topic.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to look up on the web")] string query,
        CancellationToken cancellationToken = default)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

            var result = await _httpClient.GetFromJsonAsync<DuckDuckGoResponse>(url, cancellationToken);

            if (result is null)
                return $"No results found for '{query}'.";

            var parts = new List<string>();

            if (!string.IsNullOrWhiteSpace(result.Abstract))
                parts.Add($"Summary: {result.Abstract} (Source: {result.AbstractSource})");

            if (!string.IsNullOrWhiteSpace(result.Answer))
                parts.Add($"Answer: {result.Answer}");

            foreach (var topic in result.RelatedTopics?.Take(5) ?? [])
            {
                if (!string.IsNullOrWhiteSpace(topic.Text))
                    parts.Add($"- {topic.Text}");
            }

            return parts.Count > 0
                ? string.Join("\n", parts)
                : $"No detailed results found for '{query}'. Try rephrasing the query.";
        }
        catch (Exception ex)
        {
            return $"Search failed for '{query}': {ex.Message}";
        }
    }

    private sealed class DuckDuckGoResponse
    {
        [JsonPropertyName("Abstract")]
        public string? Abstract { get; set; }

        [JsonPropertyName("AbstractSource")]
        public string? AbstractSource { get; set; }

        [JsonPropertyName("Answer")]
        public string? Answer { get; set; }

        [JsonPropertyName("RelatedTopics")]
        public List<RelatedTopic>? RelatedTopics { get; set; }
    }

    private sealed class RelatedTopic
    {
        [JsonPropertyName("Text")]
        public string? Text { get; set; }

        [JsonPropertyName("FirstURL")]
        public string? FirstURL { get; set; }
    }
}

using System.ComponentModel;
using System.Text;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capability so the agent can record and recall findings during research.
/// </summary>
public sealed class NoteTool
{
    private readonly List<(string Title, string Content)> _notes = [];

    [Description("Saves a research note with a title and content. Use this to record important findings during research.")]
    public string SaveNote(
        [Description("A short title summarizing the note")] string title,
        [Description("The detailed content of the note")] string content)
    {
        _notes.Add((title, content));
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description("Retrieves all saved research notes. Use this to review findings before writing a summary.")]
    public string GetAllNotes()
