            var parts = new List<string>();

            if (!string.IsNullOrWhiteSpace(result.Abstract))
                parts.Add($"Summary: {result.Abstract} (Source: {result.AbstractSource})");

            if (!string.IsNullOrWhiteSpace(result.Answer))
                parts.Add($"Answer: {result.Answer}");

            foreach (var topic in result.RelatedTopics?.Take(5) ?? [])
