using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent.Tools;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient through the MEAI abstraction ---
var openAiClient = new OpenAIClient(apiKey);
IChatClient chatClient = openAiClient.GetChatClient(modelId).AsIChatClient();

// --- Instantiate tools ---
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

var webSearch = new WebSearchTool(httpClient);
var noteTool = new NoteTool();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearch.SearchWebAsync),
    AIFunctionFactory.Create(noteTool.SaveNote),
    AIFunctionFactory.Create(noteTool.GetAllNotes),
};

// --- Create the agent with instructions and guardrails ---
const string Instructions = """
    You are a research assistant. Your job is to thoroughly research a topic the user provides.

    Follow this workflow:
    1. Break the topic into 2-3 specific sub-questions.
    2. Use the SearchWebAsync tool to search for each sub-question.
    3. Use the SaveNote tool to record key findings from each search.
    4. After gathering enough information, use GetAllNotes to review your findings.
    5. Produce a well-structured summary with sections, citing what you found.

    Be thorough but concise. Always save notes before summarizing.
    """;

var agent = new ChatClientAgent(
    chatClient,
    instructions: Instructions,
    name: "ResearchAgent",
    description: "An AI agent that researches topics using web search and note-taking tools.",
    tools: tools);

// --- Run the agent ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       Research Agent (MAF + MEAI)    ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\nResearching: {topic}\n");

var session = await agent.CreateSessionAsync();
var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
});

await foreach (var update in agent.RunStreamingAsync(topic, session, runOptions))
{
    Console.Write(update.Text);
}

Console.WriteLine();

static string PromptForTopic()
{
    Console.Write("Enter a topic to research: ");
    var input = Console.ReadLine()?.Trim();
    return string.IsNullOrWhiteSpace(input)
        ? "the history and impact of the World Wide Web"
        : input;
}

